"""
mkt-original | Numbers | chapters 22–24
Run: python3 scripts/zc-original-numbers-22-24-fill.py

The Balaam narrative: a Gentile diviner hired to curse Israel who instead delivers
four prophetic oracles of blessing. Key lexical items: qesamim (divination fees, 22:7),
leśatan lo (as an adversary/satan, 22:22), peh ha'aton (the donkey's mouth, 22:28),
ne'um (prophetic utterance formula), setum ha'ayin (whose eye is opened, 24:3),
kokhav miya'aqov (star from Jacob, 24:17), shevet (scepter/rod/tribe).

Ch 22: Balak's embassy, divine permission/prohibition tension, the donkey pericope.
Ch 23: First and second oracles — national distinctiveness, divine immutability, no
       divination against Israel.
Ch 24: Third oracle (Spirit of God; tents of Jacob), fourth oracle (Star from Jacob —
       the primary messianic oracle of Numbers).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "22": {
    "1": "<p><strong>vayisu benei Yisra'el vayachanu be'arvot Mo'av</strong>: 'The Israelites traveled on and camped in the plains (<em>'arvot</em>) of Moab.' The <em>'arvot</em> (pl. of <em>'aravah</em>, steppe/plain) are the flat arid floodplains east of the Jordan opposite Jericho — a staging area for the Canaan entry narrative that will dominate the rest of the Torah. The phrase <em>me'ever leYarden Yericho</em> (across the Jordan from Jericho) is the geographical anchor of the final wilderness position; from here Israel will cross over. The entire Balaam section (chs.22-24) occurs at this liminal location — Israel on the threshold of the promised land, seen from outside by Balak and Balaam.</p>",
    "2": "<p><strong>vayar Balaq ben Tzippor et kol asher asah Yisra'el la'Emori</strong>: Balak son of Zippor sees (<em>vayar</em>) what Israel did to the Amorites — the verb of perception opens the narrative. <em>Balaq</em> means 'destroyer/devastator'; <em>Tzippor</em> means 'bird' (the same word as <em>tzipporah</em>, Moses's wife's name). Balak is king of Moab (v4), though interestingly the narrative will name Midian's elders alongside Moab (v4,7) — a detail that will resurface in the Baal Peor incident (ch.25). His fear is based on intelligence about Israel's recent military victories over Sihon and Og (chs.21).</p>",
    "3": "<p><strong>vayagor Mo'av mippenei ha'am me'od ki rav hu vayaqots Mo'av mippenei benei Yisra'el</strong>: Two verbs describe Moab's psychological state: <em>yagor</em> (was afraid/dreaded) and <em>quts</em> (was in dread/loathing). The root <em>quts</em> is strong — it can mean to be overcome with dread, even physically sickened. The phrase <em>ki rav hu</em> (because they are so numerous) echoes the Egyptian reaction in Exod 1:9 (<em>rav veatzum mimmenu</em>, too many and powerful for us) — Moab's fear mirrors Pharaoh's, setting up a structural parallel between the Balaam narrative and the Exodus.</p>",
    "4": "<p><strong>kha'asher yilchoch hashor et yerek hassadeh</strong>: The simile — 'the way an ox licks up the grass of the field' — is vivid and unusual: Israel is compared to an ox that devours everything it encounters. The Moabite leaders address the <em>ziqnei Midyan</em> (elders of Midian), suggesting a political alliance of Transjordanian peoples against Israel. Balak's request for Balaam's curse follows immediately from this fear — he cannot defeat Israel militarily and turns to supernatural means.</p>",
    "5": "<p><strong>vayishlach mal'akhim el Bil'am ben Be'or Petorah asher al hanahar</strong>: Balaam son of Beor at Pethor 'which is near the River' (<em>hanahar</em> = the Euphrates, always the referent when unspecified in biblical Hebrew). Balaam's origin near the Euphrates places him in the region of Aram/northern Mesopotamia — the same region as Abraham's homeland (Haran), Laban, and Mesopotamian divination traditions. <em>Bil'am ben Be'or</em>: Beor is also the name of Bela son of Beor, king of Edom (Gen 36:32; 1 Chr 1:43), raising the question of whether Balaam has Edomite connections, though the geographic description points to Mesopotamia. The phrase <em>eretz benei ammo</em> (land of his people) is ambiguous — 'his kinsmen' or possibly a place name Amaw (attested in Akkadian sources).</p>",
    "6": "<p><strong>arah na li et ha'am hazeh ki atzum hu mimmeni</strong>: 'Curse (<em>arah</em>) for me this people.' Balak uses three curse terms across the narrative: <em>arar</em> (to curse, the strongest term, v6), <em>qabav</em> (to curse/injure, vv.11,17), and <em>za'am</em> (to denounce). The belief that professional cursing can determine military outcomes is well-attested in ancient Near Eastern sources (Egyptian execration texts, Mesopotamian cursing rituals). Balak's theology is that supernatural word-power can overcome superior military strength — a theology the narrative systematically dismantles. His final phrase, <em>ki yadati et asher tevarekh mevorakh ve'asher ta'or yu'ar</em> (because I know that those you bless are blessed and those you curse are cursed), grants Balaam enormous authority — which will be entirely redirected by YHWH.</p>",
    "7": "<p><strong>vayelechu ziqnei Mo'av veziqnei Midyan uqesamim beyadam</strong>: 'The elders of Moab and Midian went, with divination fees (<em>qesamim</em>) in their hands.' The word <em>qesamim</em> is plural of <em>qesem</em> (divination, augury) — here it probably refers to the payment artifacts or tokens used in the divination trade rather than actual acts of divination. The term establishes Balaam's professional identity as a paid diviner, an occupation known throughout the ancient world. Alternatively, <em>qesamim beyadam</em> could mean they carried instruments of divination — physical tools of the trade as authentication of Balak's request.</p>",
    "8": "<p><strong>vayomer alehem linu poh halayla vahashivoti etchem davar ka'asher yedabber YHWH elai</strong>: Balaam's response is remarkable: he says he will report <em>ka'asher yedabber YHWH elai</em> (what YHWH speaks to me). A Mesopotamian diviner who knows the divine name YHWH and receives communication from him — the text presents this without surprise, apparently accepting that YHWH communicates with non-Israelite prophets. This raises significant questions about the boundaries of YHWH's revelation. Balaam's willingness to wait for YHWH's word, rather than immediately accepting the payment, suggests a genuine prophetic constraint.</p>",
    "9": "<p><strong>vayavo Elohim el Bil'am vayomer mi ha'anashim ha'eleh immakh</strong>: 'God came to Balaam.' The divine approach is initiated by God, not by Balaam's divination techniques — a detail that underscores YHWH's sovereign control of this episode. The divine question 'Who are these men with you?' is not a request for information but an invitation to narrative — the standard opener for divine interrogation (cf. Gen 3:9 to Adam, 4:9 to Cain). Note the shift between <em>Elohim</em> (God) here and <em>YHWH</em> in v8 — both are used interchangeably in this narrative for the divine being who speaks to Balaam.</p>",
    "10": "<p><strong>vayomer Bil'am el haElohim Balaq ben Tzippor melekh Mo'av shalach elai</strong>: Balaam reports Balak's message to God — a form of transparent prayer-report. The fact that Balaam addresses the Deity as <em>haElohim</em> (the God) — with the definite article — suggests either that he recognizes YHWH as <em>the</em> true God, or that this is simply the formulaic way a non-Israelite would refer to the deity speaking to him.</p>",
    "11": "<p>Balaam quotes Balak's message: 'A people has come out of Egypt and covers (<em>yechasse</em>, covers/conceals, from <em>kasah</em>) the face of the land.' The same metaphor as v4 but using a different verb. The phrase <em>chakkah li oto</em> (curse them for me) uses <em>qabav</em> (to curse, from an Aramaic root suggesting bore-through or wound); the same root appears in Job 3:8 and 5:3 in contexts of cursing and rooting out. Balak's revised request — 'perhaps I can fight them and drive them out' — shows military desperation as the underlying motive.</p>",
    "12": "<p><strong>vayomer Elohim el Bil'am lo telekh immahem lo te'or et ha'am ki varukh hu</strong>: The direct divine prohibition: 'Do not go with them, and do not curse the people, because they are blessed (<em>varukh hu</em>).' The logic is decisive: YHWH's blessing on Israel makes it impossible for a curse to land. The benediction pronounced on Abraham (Gen 12:2-3) — 'I will bless those who bless you and curse those who curse you' — is the theological foundation of YHWH's refusal. Balaam cannot curse what God has blessed — the operative principle is divine sovereignty over the power of speech-acts.</p>",
    "13": "<p><strong>vayaqom Bil'am baboqer vayomer el sarei Valaq lechu el artzechem ki me'en YHWH letiti halekh immakem</strong>: Balaam complies with the prohibition and dismisses the first delegation. His report — 'YHWH has refused to let me go with you' — uses <em>me'en</em> (refuses, from <em>ma'an</em>, to refuse/decline), a strong term of willing refusal. The divine name YHWH appears explicitly in Balaam's speech — a foreign diviner who names YHWH as his divine constraint. This is a remarkable datum for understanding the text's view of divine revelation beyond Israel.</p>",
    "14": "<p>The Moabite princes return with a simple report: 'Balaam refused to come with us.' The verb is the same <em>ma'an</em> — but applied to Balaam rather than YHWH, as if the princes understood Balaam's refusal as his own choice rather than divine compulsion. Whether this reflects their interpretation or Balaam's phrasing to them (v13) is ambiguous.</p>",
    "15": "<p><strong>vayoseph 'od Balaq shloch sarim rabbim venichbadim me'elleh</strong>: 'Balak sent again (<em>vayoseph</em>, and he added/repeated) more numerous and distinguished (<em>nichbadim</em>, heavy/weighty in honor) princes.' The escalation follows the standard diplomatic pattern of intensifying embassies — more representatives, more prominent, presumably with more silver. <em>Nichbadim</em> from <em>kaved</em> (heavy, honored) — the same root as <em>kavod</em> (glory/honor/weight); these are literally weighty men.</p>",
    "16": "<p>Balak's message through the second delegation escalates the request: 'Please do not let anything keep you from coming to me.' The imperative <em>al na timana</em> (please do not be withheld/prevented) uses <em>mana'</em> (to withhold/prevent), suggesting Balak is aware that Balaam claimed some external constraint. He is trying to remove that constraint by appealing more urgently.</p>",
    "17": "<p><strong>kabbed akabedkha me'od</strong>: 'I will honor you very greatly.' The infinitive absolute construction <em>kabbed akabedkha</em> (honor-honoring I will honor you) is emphatic — the doubled <em>kaved</em> root intensifies the promise. Balak promises whatever Balaam asks. The offer of maximum payment frames what follows: Balaam's refusal to accept is not from lack of incentive but from genuine prophetic constraint (cf. v18).</p>",
    "18": "<p><strong>lo ukhal la'avor et pi YHWH la'asot qetannah o gedolah</strong>: 'I cannot go beyond the mouth (<em>pi</em>) of YHWH to do anything small or great.' The phrase <em>'avar et pi</em> (go beyond the mouth/command of) is an idiom for transgressing a divine command; <em>pi YHWH</em> (the mouth of YHWH) stands metonymically for the divine word. The formula 'small or great' (<em>qetannah o gedolah</em>) is a merism for anything whatsoever. This verse establishes Balaam's genuine prophetic constraint — he cannot manufacture a curse that YHWH has not sanctioned, regardless of the payment offered.</p>",
    "19": "<p><strong>ve'attah shevu na vezeh gam attem halaylah ve'eda'ah mah yoseph YHWH dabber immi</strong>: Balaam asks the second delegation to stay overnight while he inquires further of YHWH — using <em>yoseph</em> (will add/say additionally). This verse is theologically complex: God already said no (v12). Balaam's reopening of the question has been read as (a) genuine prophetic uncertainty about whether the new situation changes anything, (b) moral ambiguity — he wants to go and is looking for permission, or (c) standard prophetic practice of re-inquiring. The narrative's irony is that YHWH will permit the trip (v20) but then be angry that Balaam went (v22).</p>",
    "20": "<p><strong>vayavo Elohim el Bil'am laylah vayomer lo im liqro lecha ba'u ha'anashim qum lekh ittam ve'akh et hadavar asher adabber elekha oto ta'aseh</strong>: God's conditional permission — 'if these men have come to summon you, rise and go with them — but do only the word I speak to you.' The conditional <em>im</em> clause is significant: <em>liqro lecha ba'u</em> (if they came to summon you) may suggest that YHWH is taking Balaam at his word about the second embassy's purpose. The limitation — <em>ve'akh et hadavar asher adabber elekha oto ta'aseh</em> (only the word I speak to you, that you shall do) — is the same restriction as before, but now with permission to travel.</p>",
    "21": "<p><strong>vayaqom Bil'am baboqer vayachavosh et atono vayeelekh im sarei Mo'av</strong>: 'Balaam got up in the morning, saddled his donkey, and went with the Moabite princes.' The donkey (<em>'aton</em>, a female donkey) is now introduced as a character in her own right. The saddling of one's own donkey (<em>vayachavosh</em>) is a mark of urgency or of personal action without servants — Abraham does the same before the Akedah (Gen 22:3). The speed of Balaam's preparation and departure suggests eagerness, which may account for YHWH's anger in v22.</p>",
    "22": "<p><strong>vayichar af Elohim ki holekh hu vayityatsev mal'akh YHWH baderekh leśatan lo</strong>: 'God's anger burned because he was going, and the angel of YHWH positioned himself in the road <em>leśatan lo</em>.' The phrase <em>leśatan lo</em> (as a satan/adversary to him) uses the root <em>śatan</em> (to oppose, to act as an adversary) — the same root as the noun <em>śatan</em> (adversary/accuser, used of the figure in Job 1-2 and Zech 3:1-2). Here it is a functional description: the angel acts as an opposing force in the road. The theological tension between v20 (permission to go) and v22 (anger that he went) has generated much discussion: either God is angry at Balaam's eagerness/motivation, or the narrative juxtaposes two divine responses that reflect the complexity of prophetic permission.</p>",
    "23": "<p><strong>vatere ha'aton et mal'akh YHWH nitsav baderekh vecharbo shelufah beyado</strong>: The donkey sees the angel with a drawn sword — the same sword posture as the cherubim blocking Eden (Gen 3:24 <em>lahat hacherev hammithappekhet</em>) and the commander of YHWH's army at Jericho (Josh 5:13). The donkey's perception precedes Balaam's — a deliberate reversal: the animal sees what the prophet cannot. Balaam beats the donkey three times (vv.23,25,27) — the triple beating intensifies the irony of a famous seer being spiritually blinder than his pack animal.</p>",
    "24": "<p>The angel moves to 'a narrow path between the vineyards with a wall on each side' — the geography constrains the donkey's escape options and increases the pressure. The progressive narrowing of the path (field → walled path → no room to turn) mirrors Balaam's progressive entrapment by the divine will he is trying to circumvent.</p>",
    "25": "<p><strong>vatilaches ha'aton el haqir vatilchotz et regel Bil'am el haqir vayoseph lehakotah</strong>: 'The donkey pressed (<em>tilaches</em>, to press/squeeze, from <em>lachats</em>) herself against the wall, crushing Balaam's foot against it.' <em>Lachats</em> is used in Exod 3:9 and elsewhere for the oppression of Israel in Egypt — the same root. The donkey's foot-crushing is involuntary self-defense; Balaam's beating is the response of a man who cannot see what his mount is responding to.</p>",
    "26": "<p>The angel moves again to a place where 'there was no room to turn either right or left' — <em>ein derekh limnot yamin ushemol</em>. The progressively blocked path is a spatial enactment of the theological principle that YHWH's will has no available bypass: every route is closed, just as every route for cursing Israel will be closed.</p>",
    "27": "<p><strong>vatere ha'aton et mal'akh YHWH vattirbats tachat Bil'am</strong>: The donkey lies down under Balaam — a final act of passive resistance. When beating no longer works, the animal simply stops. <em>Tirbats</em> (lay down) uses the <em>ravats</em> root, associated with an animal lying at rest (as in Gen 49:9, Isa 11:6-7). Balaam's rage ('he struck her with his staff') is the rage of a man whose professional tools (words, spiritual perception) are entirely useless while his draft animal has superior discernment.</p>",
    "28": "<p><strong>vayiftach YHWH et pi ha'aton vatomer leBil'am meh asiti lekha ki hikkitani zeh shalosh regalim</strong>: 'The LORD opened (<em>vayiftach</em>, from <em>patach</em>, to open) the mouth of the donkey.' The rare miracle of an animal speaking is paralleled in the narrative by the opening of Balaam's eyes (v31) — both openings are YHWH's act. The donkey's first words are a legal question: 'What have I done to you that you have beaten me three times?' The <em>shalosh regalim</em> (three times) will later echo in the donkey's argument (v30) that her past perfect service is proof of her current reliability. The same phrase <em>shalosh regalim</em> means 'three pilgrimage festivals' in Exod 23:14 — an incidental pun of uncertain significance.</p>",
    "29": "<p><strong>vayomer Bil'am la'aton ki hit'alalt bi lul yesh cherev beyadi ki atah haragtikh</strong>: Balaam's response — 'If only I had a sword in my hand, I would kill you now' — is dramatic irony: the angel has a drawn sword (v23), Balaam has none, and the donkey is the one who has saved his life (v33). Balaam's anger blinds him to the reversal: he threatens death to the creature that has been preserving him from death.</p>",
    "30": "<p><strong>vatomer ha'aton el Bil'am halo anokhi atonkha asher rakhavta alai me'odekha hayom hazeh</strong>: The donkey's argument: 'Am I not your donkey (<em>atonkha</em>) that you have ridden (<em>rakhavta</em>) your whole life?' The phrase <em>me'odekha</em> (from your youth, or all along) is unusual — <em>me'od</em> normally means 'very/greatly' but here functions as 'for a long time.' The donkey appeals to their relationship history as evidence that her current behavior is anomalous and therefore meaningful. Balaam can only say 'No' — he concedes the donkey's prior reliability, which should raise a question he has not yet asked.</p>",
    "31": "<p><strong>vayigal YHWH et einei Bil'am vayar et mal'akh YHWH nitsav baderekh</strong>: 'The LORD uncovered (<em>vayigal</em>, from <em>galah</em>, to uncover/reveal) Balaam's eyes.' The vocabulary of revelation: <em>galah</em> is the root of all the <em>galut</em>/exile language (uncovering = exposure/vulnerability) but also of divine disclosure (cf. the same root in <em>galui einayim</em>, eyes wide open, in 24:4). Balaam now sees what his donkey has seen all along and bows down — the seer is humbled by his blindness. The angel's drawn sword retroactively explains the donkey's behavior and vindicates her.</p>",
    "32": "<p><strong>vayomer elav mal'akh YHWH al mah hikkita et atonkha zeh shalosh regalim hineh anokhi yatzati leśatan ki yarath haderekh lenaddi</strong>: The angel's rebuke uses the <em>śatan</em> root again — 'I came out as an adversary (<em>leśatan</em>) because your way is reckless before me.' The term <em>yarath</em> (headlong, precipitous) suggests recklessness or rushing — Balaam's eagerness to go was itself the problem, not just the going. The angel's statement reveals that Balaam's motivations, not just his actions, were under divine scrutiny.</p>",
    "33": "<p><strong>vatire'ani ha'aton vatit negh lefanai zeh shalosh regalim ulai natah meacharai ki attah gam-otecha harasgti ve'othah hecheyeti</strong>: The angel's final word: 'If she had not turned away from me these three times, I would certainly have killed you, though I would have spared her.' The donkey's 'disobedience' to Balaam was obedience to the angel — it saved Balaam's life. The irony is complete: the beast Balaam wanted to kill was his unwitting protector. This functions as a narrative parable about Balaam's entire enterprise — what looks like resistance to his plans is actually divine preservation.</p>",
    "34": "<p><strong>vayomer Bil'am el mal'akh YHWH chatati</strong>: 'Balaam said to the angel of YHWH: I have sinned.' The confession is immediate and appears genuine. The offer to return home is sincere — but the angel gives the same permission God gave in v20: go, but speak only my words. The entire episode seems to have functioned as a divine interrogation of Balaam's motivation, a stripping away of his prophetic pretensions before the oracles, ensuring that what follows is entirely YHWH's word, not Balaam's craft.</p>",
    "35": "<p><strong>lekh im ha'anashim ve'efes et hadavar asher adabber elekha oto tedabber</strong>: The angel repeats the divine constraint: 'Go, but the word I speak to you, speak only that.' The word <em>efes</em> (but/nevertheless) introduces the limitation clause. This verse establishes the absolute prophetic constraint under which all four subsequent oracles will be delivered — Balaam speaks YHWH's word and nothing else, regardless of what Balak commands.</p>",
    "36": "<p><strong>vayishma Balaq ki va Bil'am vayetse liqrattow el ir Mo'av</strong>: Balak goes out to meet Balaam at the city of Moab on the Arnon — the Arnon River was the northern boundary of Moab. The geography establishes that Balak meets Balaam at the outermost limit of his territory, the maximum advance to greet an honored guest.</p>",
    "37": "<p><strong>vayomer Balaq el Bil'am halo shaloch shalacgti elekha liqro lakh lammah lo halachta elai</strong>: Balak's rebuke is tinged with both disappointment and political face-saving: 'Did I not urgently send for you? Why didn't you come immediately? Am I not able to honor you richly?' The infinite absolute <em>shaloch shalachti</em> (urgently/emphatically sent) mirrors Balaam's own emphatic speech. Balak assumes Balaam delayed because of insufficient honor offered — he still doesn't understand the divine constraint.</p>",
    "38": "<p><strong>vayomer Bil'am el Balaq hineh bati elekha attah hayukhal adabber me'umah haddavar asher yasim Elohim befumi oto adabber</strong>: 'The word that God places (<em>yasim</em>, puts/sets) in my mouth — that I will speak.' The metaphor of God placing words in the prophet's mouth (<em>yasim befumi</em>) is the standard biblical idiom for prophetic inspiration: Exod 4:15 (God to Moses about Aaron), Jer 1:9 (YHWH touches Jeremiah's mouth), Ezek 3:3 (eating the scroll). Balaam presents himself as a passive receptor of divine speech — a claim the narrative endorses.</p>",
    "39": "<p>Balaam accompanies Balak to Kiriath-huzoth. The place name <em>Qiryat Chutsot</em> may mean 'City of Streets/Plazas' — a significant urban center in Moab. The journey to multiple vantage points (Bamoth-baal, Pisgah, Peor) across the oracles mirrors the visual-dominance strategy of Balak: show Balaam the people from the best angle to generate a curse. Each time YHWH redirects the visual encounter into a blessing.</p>",
    "40": "<p><strong>vayizbach Balaq bakar vetson vayishallach leBil'am ulasarim asher itto</strong>: Balak sacrifices cattle and sheep — preparatory meals before seeking oracular speech. The sending of portions to the princes and to Balaam is standard Near Eastern banquet hospitality before a formal religious ceremony. The sacrifice is Moabite, not Levitical — the narrative does not comment on the appropriateness of the food but simply records the social ritual.</p>",
    "41": "<p><strong>vayehi vaboqer vayiqach Balaq et Bil'am vaya'alehu bamot ba'al</strong>: 'The next morning Balak took Balaam up to <em>Bamoth-baal</em>.' <em>Bamot</em> (high places, cultic elevated platforms) were ubiquitous in Canaanite religion — <em>bamot ba'al</em> is specifically a Baal high place. From there Balaam 'could see a portion of the Israelites' (<em>qetseh ha'am</em>, the edge/extremity of the people). Balak's strategy of showing only a portion (rather than the full camp) will be varied at Pisgah (also partial, 23:13) and at Peor (overlooks the desert, not the camp). The visual frame matters for oracle purposes in ancient divination practice.</p>"
  },
  "23": {
    "1": "<p><strong>vayomer Bil'am el Balaq bane li vezeh shiv'ah mizbechot vahakon li vezeh shiv'ah farim veshiv'ah eilim</strong>: Balaam commands seven altars, seven bulls, seven rams — a sacral number prominent in ancient sacrificial contexts across cultures (Ugaritic texts mention seven-fold sacrificial preparations). The number seven signals sacred completeness. Notably, Balaam directs the construction and sacrifice — he is functioning as a cultic officiant despite being a Gentile diviner, and the text presents this without critique.</p>",
    "2": "<p>Balak complies exactly with Balaam's prescription. The narrative emphasizes Balak's obedience to Balaam's ritual instructions throughout — an ironic reversal of the expected patron-client relationship. The king becomes the ritual assistant to the diviner he hired to serve him.</p>",
    "3": "<p><strong>vayomer Bil'am leBaltq hityatsev al olatkha ve'elchah ulay yiqreh YHWH liqrati</strong>: Balaam instructs Balak to 'stand by your burnt offering while I go.' The verb <em>yiqreh</em> (will happen/meet) from <em>qarah</em> is deliberately vague — 'perhaps something will happen to me' — suggesting Balaam is not certain of the mode of divine communication he will receive. He will 'report what YHWH shows me' (<em>mah yar'eni</em>). The uncertainty of the encounter preparation is authentic to prophetic experience: the prophet positions himself for encounter but cannot control its occurrence.</p>",
    "4": "<p><strong>vayiqar Elohim el Bil'am vayomer elav et shiv'at hamizbeachot arakhti</strong>: God meets Balaam and Balaam reports his sacrificial preparations. The verb <em>vayiqar</em> (met/encountered) is from <em>qarah</em> (to happen upon, to meet by chance or in encounter) — the same root Balaam used in v3 when he hoped God would 'happen' to him. The encounter formula underscores divine initiative: God comes to Balaam, not vice versa. Balaam's report of his sacrifice preparations is a form of presenting his prophetic credentials to the deity.</p>",
    "5": "<p><strong>vayasem YHWH davar beffi Bil'am</strong>: 'The LORD put a word in Balaam's mouth.' The word-in-mouth idiom for prophetic inspiration appears in its clearest form here — the same verb <em>yasim</em> (put/place) Balaam used in 22:38. This establishes that the first oracle (vv.7-10) is entirely YHWH's composition, not Balaam's craft. Whatever Balaam's intentions or background, the words delivered are divine words placed in a human mouth.</p>",
    "6": "<p>Balak stands by his burnt offering with all the Moabite princes as Balaam returns — the elaborate ritual setting up of sacrifice was preparation for this moment of prophetic address. The princes as audience make the oracle a public state event, not a private consultation.</p>",
    "7": "<p><strong>vayissa meshalow vayomar min Aram yancheni Balaq</strong>: 'He took up (<em>yissa</em>, lifted up) his oracle (<em>mashal</em>) and said.' The term <em>mashal</em> is translated as oracle/parable/proverb — it is the genre label for Balaam's four speeches. The root <em>mashal</em> means 'to be like/comparable to' (the comparative function) and also 'to rule over/govern' — both semantic fields are active in prophetic <em>meshalim</em>. The opening of the first oracle identifies the setting: Aram (northern Mesopotamia) and the mountains of the east — Balaam's homeland, from which he was summoned by Moab.</p>",
    "8": "<p><strong>mah eqov lo qabboh El umah ez'om lo za'am YHWH</strong>: 'How can I curse whom God has not cursed? How can I denounce whom YHWH has not denounced?' Three curse roots appear across the oracles: <em>arar</em> (structural curse), <em>qabav</em> (to wound/bore-curse), and <em>za'am</em> (to denounce/be furious at). The rhetorical questions are unanswerable — the entire metaphysics of ancient cursing depends on the deity endorsing the curse; without divine sanction, the words have no power. Balaam does not merely refuse to curse — he states the ontological impossibility of cursing what God has blessed.</p>",
    "9": "<p><strong>ki merosh tsurim er'enu umigeva'ot ashurennu hen am levadad yishkon uvagoyim lo yithchashav</strong>: 'From the rocky peaks I see them... here is a people who dwell alone (<em>levadad yishkon</em>) and do not count themselves among the nations.' The phrase <em>am levadad</em> (a people of aloneness) is Israel's essential character — set apart, not assimilated into the nations' categories. Later Jewish interpretation (Midrash Bamidbar Rabbah) reads this as divine comfort: Israel's distinctiveness is the source of their preservation. Balaam perceives from Baal's high place what Baal cannot provide: the theological truth about Israel's unique status.</p>",
    "10": "<p><strong>mi manah afar Ya'aqov umispar et roba' Yisra'el</strong>: 'Who can count the dust of Jacob or number the fourth part of Israel?' The uncountable dust is the Abrahamic promise language (Gen 13:16: 'if anyone can count the dust of the earth, so your offspring can be counted'). Balaam blesses Israel with the terms of the Abrahamic covenant without knowing the covenant explicitly — YHWH has placed this blessing in his mouth. The oracle closes with the personal wish: 'May I die the death of the upright (<em>yesharim</em>, righteous/straight ones), may my end be like theirs' — Balaam desires Israel's destiny even as he serves Moab's enemy purposes.</p>",
    "11": "<p><strong>vayomer Balaq el Bil'am meh asita li laqov oyvai laqachticha vahineh berakhta varakh</strong>: Balak's shocked response: 'What have you done to me? I took you to curse my enemies and you have blessed them — blessed (<em>berakhta varakh</em>)!' The doubled blessing idiom emphasizes the completeness of what Balaam delivered. Balak's frustration is understandable from his perspective, but the narrative invites the reader to recognize that the blessing is exactly right — Balaam was commissioned by YHWH, not Balak.</p>",
    "12": "<p><strong>vayaan vayomer halo et asher yasim YHWH beffi oto eshmor ledabber</strong>: 'Must I not be careful to say what YHWH puts in my mouth?' Balaam's defense is the same prophetic constraint of 22:38 — he simply delivers what is placed in his mouth. The word <em>eshmor</em> (I must guard/keep) suggests active fidelity to the received word, not passive transmission. The prophet guards the word as a custodian of divine speech.</p>",
    "13": "<p>Balak proposes a new vantage point — only the edge of the camp, not the full mass. His theory is that a partial view of Israel (rather than the overwhelming totality) might enable a partial curse. The change of perspective strategy is magical thinking: that changing the angle of vision changes the divine verdict. The narrative will refute this in the second oracle.</p>",
    "14": "<p><strong>vayiqachehu sadeh Tsofim el rosh haPisgah</strong>: Pisgah — the same mountain from whose summit Moses will later see the promised land before his death (Deut 34:1). The geographic resonance is significant: the place where Balaam speaks oracles of blessing becomes the place where Moses receives his final vision of the covenant's fulfillment. Seven new altars, seven new animals — the full ritual repeated.</p>",
    "15": "<p>Balaam instructs Balak to stand by his offering while he goes to meet YHWH. The second oracle setup mirrors the first — the repetition establishes that Balaam's prophetic procedure is consistent and the outcome will be YHWH's, not varied by Balak's strategy of changing locations.</p>",
    "16": "<p><strong>vayiqar YHWH el Bil'am vayasem davar beffi vayomer shuv el Balaq vekhoh tedabber</strong>: YHWH meets Balaam and places words in his mouth — the exact formula of v5. The identity of the divine speaker shifts between <em>YHWH</em> and <em>Elohim</em> across the chapter, but the action is identical. The words placed in Balaam's mouth are again entirely YHWH's composition.</p>",
    "17": "<p>Balak is standing by his burnt offering — the patient posture of waiting for prophetic word. His question 'What has YHWH said?' (<em>mah dibber YHWH</em>) acknowledges YHWH as the source of Balaam's oracle — a remarkable concession from a Moabite king. The story has effectively educated Balak about who controls the prophetic word even if he cannot accept the content of the oracles.</p>",
    "18": "<p><strong>vayissa meshalow vayomar qum Balaq ushma hazinah adai ben Tzippor</strong>: The second oracle begins with a call to attention: 'Arise, Balak, and hear! Give ear to me, son of Zippor!' (<em>hazinah</em>, from <em>azan</em>, to give ear/listen attentively). This is more direct and authoritative than the first oracle's scenic opening — Balaam addresses Balak personally. The imperatives escalate the prophetic authority.</p>",
    "19": "<p><strong>lo ish El viykhazev uven adam veyitneham</strong>: 'God is not a man who lies, nor a son of man who changes his mind.' The verse is one of the deepest theological statements in Numbers — divine immutability articulated by a Gentile prophet. The contrast <em>ish...ben adam</em> (man...son of man) establishes the human-divine distinction: humans lie (<em>kazav</em>) and repent/change their minds (<em>nicham</em>). The question 'Does he speak and not act?' is answered by the oracles themselves — YHWH spoke blessing over Israel, and it will not be reversed. This verse becomes a key text for divine aseity and reliability (cf. 1 Sam 15:29, which echoes it verbatim in a different context).</p>",
    "20": "<p><strong>hineh varech laqachti uvarakh velo ashivenah</strong>: 'I have received a command to bless; he has blessed, and I cannot reverse it.' The verb <em>laqachti</em> (I have received/taken) describes Balaam as the recipient of a blessing already given — he did not compose it or have authority over it. The blessing is YHWH's prior decision (<em>varakh velo ashivenah</em>, he blessed and I cannot reverse it). The prophet cannot revoke what the deity has determined — prophetic speech is declarative of divine reality, not creative of it.</p>",
    "21": "<p><strong>lo hibit aven beYa'aqov velo ra'ah amal beYisra'el YHWH Elohav immo</strong>: 'He has not looked upon (<em>hibit</em>) iniquity in Jacob nor has he seen (<em>ra'ah</em>) trouble in Israel.' This verse is theologically contested: does it mean (a) YHWH perceives no sin in Israel (impossible given the wilderness narrative), or (b) YHWH does not look on Israel as accursed/condemned (i.e., no curse-worker can penetrate the divine favor), or (c) no divination-magic (<em>aven</em> can mean both wickedness and divination) has been found working against Israel. The context favors (b) or (c): in a chapter about Balaam's inability to curse, the claim is that no magical-cursing power (<em>aven, amal</em>) is effective against Israel because YHWH is with them. The clause <em>YHWH Elohav immo</em> (YHWH his God is with him) is the protective reality that nullifies curse-attempts.</p>",
    "22": "<p><strong>El motzi'am miMitsrayim ketho'afot re'em lo</strong>: 'God brought them out of Egypt — like the horns of a wild ox (<em>re'em</em>) for him.' The <em>re'em</em> is the wild ox/aurochs (<em>Bos primigenius</em>, now extinct) — the most powerful bovine creature known in the ancient world. Its horns (<em>to'afot</em>, the exaltation/horns) represent irresistible power. The Exodus is framed as a display of divine wild-ox power — uncageable, unstoppable strength that liberated Israel. The LXX reads <em>monokeros</em> (one-horned), which entered the Latin Vulgate as <em>unicornis</em> — hence KJV's 'unicorn' in this verse.</p>",
    "23": "<p><strong>ki lo nachash beYa'aqov velo qesem beYisra'el</strong>: 'There is no omen (<em>nachash</em>, from <em>nachash</em>, to divine/observe omens — the same root as 'serpent'!) that works against Jacob, no divination (<em>qesem</em>) that prevails against Israel.' The irony is profound: Balaam's entire expertise is <em>qesem</em> (divination), and he declares that divination cannot work against Israel. He invalidates his own professional tool in the course of the oracle. The following clause — 'at the right time it will be said of Jacob and Israel what God has done' — replaces divination with proclamation: instead of oracles determining Israel's fate, their fate will be declared after the fact as testimony to what God did.</p>",
    "24": "<p><strong>hen am kelavi yaqum uchlabbi yitnas'</strong>: 'The people rise like a lioness (<em>lavi</em>), they rouse themselves like a lion (<em>ari</em>).' The lion metaphors for Israel appear again in 24:9 — Israel as a lion that does not rest until it has devoured its prey. Jacob's blessing uses the lion metaphor for Judah (Gen 49:9), and Balaam's oracle develops this national lion image. The military connotation is clear: Israel awakens like a lion to prey, drinks the blood of the slain — victor language.</p>",
    "25": "<p>Balak's desperate compromise: 'Neither curse them nor bless them!' — the third option when the first two have both produced the wrong result. But this is impossible: YHWH's prophetic word cannot simply be suspended. The oracle must be delivered; neutral silence is not an option when the divine word has been placed in the prophet's mouth.</p>",
    "26": "<p><strong>vayaan Bil'am vayomer el Balaq halo dibbarti elekha lemor kol asher yedabber YHWH oto e'eseh</strong>: Balaam's refrain — 'Did I not tell you from the beginning that I must do everything YHWH says?' — establishes prophetic consistency. The word <em>e'eseh</em> (I shall do) is active: the prophet actively performs YHWH's commission, not passively reports it.</p>",
    "27": "<p>Balak proposes a third location: 'Maybe it will please God (<em>yiytar beeinei haElohim</em>, it will be good/right in God's eyes) for you to curse them from there.' The persistence is notable — Balak still believes the location is the variable. He has not understood that the problem is not the vantage point but YHWH's sovereign determination to bless.</p>",
    "28": "<p><strong>vayiqach Balaq et Bil'am rosh haPe'or hashaqif al penei hayeshimon</strong>: Peor overlooks <em>hayeshimon</em> (the wasteland/desert) rather than the Israelite camp — the third vantage point gives a less direct view than the previous two. This location will become infamous as the site of the Baal Peor incident (ch.25), where Israel itself commits apostasy. The same mountain from which Balaam can only bless Israel will soon be the site of Israel's worst wilderness sin.</p>",
    "29": "<p>Balaam's third oracle preparation: seven altars again, seven bulls and seven rams. The repetition of the full ritual three times has the effect of underlining that no variation in ritual preparation changes the divine outcome. The ritual theater is identical each time; only the divine word changes.</p>",
    "30": "<p>Balak's exact compliance: 'Balak did as Balaam directed and offered a bull and a ram on each altar.' The report is brief and formulaic — by the third time, the reader understands the pattern. The ritual preparation is complete; the oracle will now break the pattern of the first two.</p>"
  },
  "24": {
    "1": "<p><strong>vayar Bil'am ki tov be'einei YHWH levarech et Yisra'el velo halakh kefa'am befa'am liqrat nachashim</strong>: 'Balaam saw that it was good in YHWH's eyes to bless Israel, so he did not go as at other times to seek (<em>liqrat</em>) omens (<em>nachashim</em>).' This is a turning point: Balaam abandons his professional divination practice. The word <em>nachashim</em> (omens/divination) is from the same root as <em>nachash</em> (serpent) — the snake-omen tradition. Balaam turns instead to face the wilderness where Israel is encamped. The shift from divination to direct divine speech marks the third oracle as qualitatively different from the first two.</p>",
    "2": "<p><strong>vayissa Bil'am et einav vayar et Yisra'el shochen liShvatav vattehi alav ruach Elohim</strong>: 'He looked out and saw Israel encamped tribe by tribe (<em>liShvatav</em>, by their tribes), and the Spirit of God (<em>ruach Elohim</em>) came upon him.' The Spirit's coming on Balaam — a Gentile diviner — is the only explicit Spirit-inspiration of a non-Israelite prophet in the Pentateuch. The <em>ruach Elohim</em> formula is the same as Gen 1:2 (Spirit hovering over the waters) and Exod 31:3 (Bezalel filled with the Spirit for tabernacle craft). The visual trigger — Israel's tribal camp arrangement, the perfectly ordered sacred community — evokes the Spirit's presence.</p>",
    "3": "<p><strong>vayissa meshalow vayomar ne'um Bil'am ben Be'or une'um haggever shetum ha'ayin</strong>: The oracle formula intensifies for the third and fourth oracles: <em>ne'um</em> (utterance/oracle, the prophetic formula word) appears twice in this verse. <em>Ne'um</em> is the standard prophetic-word marker (cf. <em>ne'um YHWH</em>, oracle of YHWH, throughout the prophets). <em>Shetum ha'ayin</em> is notoriously difficult: traditionally 'whose eye is opened/unstopped' (from <em>shatam</em>, to be stopped up — the opened man is one whose eye is <em>un</em>stopped); the LXX reads <em>alethinos</em> (true/genuine). The visual faculty emphasized here is prophetic sight — Balaam's eye is the organ of revelation in this oracle.</p>",
    "4": "<p><strong>ne'um shome'a imrei El asher machazeh Shaddai yechezeh nopel ugeluy einayim</strong>: 'The utterance of one who hears the words of God, who sees a vision (<em>machazeh</em>) from the Almighty (<em>Shaddai</em>), who falls prostrate with eyes wide open (<em>geluy einayim</em>).' The prophetic credential formula is elaborate: (1) hearing God's words, (2) seeing visions from El Shaddai (the patriarchal divine name, Gen 17:1, 28:3), (3) falling prostrate while the eyes remain open. The combination of prostration and open eyes describes an ecstatic visionary state — the prophet is physically overcome but spiritually perceptive. <em>El Shaddai</em> in this context connects Balaam's prophecy to the Abrahamic covenant framework.</p>",
    "5": "<p><strong>mah tovu ohalekha Ya'aqov mishkenotekha Yisra'el</strong>: 'How beautiful (<em>mah tovu</em>) are your tents (<em>ohalekha</em>), Jacob, your dwelling places (<em>mishkenotekha</em>), Israel!' This verse became the traditional Jewish liturgical greeting sung upon entering a synagogue — <em>Mah Tovu</em>. The irony that Israel's most beautiful liturgical verse was composed by a hired Gentile diviner is noted with delight in Jewish tradition. The parallelism <em>ohalekha/mishkenotekha</em> (tents/dwelling places) and <em>Ya'aqov/Yisra'el</em> (the patriarchal names) is the standard Hebrew poetic chiasm.</p>",
    "6": "<p><strong>kinechalim nitayu kegannot alei nahar ka'ahalim nata' YHWH ka'arazim alei mayim</strong>: The fourfold simile — spreading valleys, riverside gardens, aloe trees planted by YHWH, cedars beside the waters — develops the beauty motif with lush water imagery. <em>Ahalim</em> (aloe trees) is the <em>aloeswood</em> (<em>Aquilaria</em>), a prized aromatic — one of the most valuable exotic trees in ancient trade. <em>Arazim</em> (cedars) are the towering Lebanon cedars, symbol of majesty and permanence. Israel's community is portrayed as a garden of rare, fragrant, permanent trees — an Eden metaphor.</p>",
    "7": "<p><strong>yizzal mayim midalyav vezar'o bemayim rabbim</strong>: 'Water will flow from his buckets, his seed will have abundant water.' The agricultural blessing of water abundance is followed by the political-royal oracle: 'his king will be greater than Agag, and his kingdom will be exalted.' The mention of <em>Agag</em> (king of the Amalekites, 1 Sam 15) is proleptic — anticipating the future king who will defeat Amalek. The oracle looks forward to the Davidic monarchy as the fulfillment of the national greatness it predicts.</p>",
    "8": "<p><strong>El motsi'o miMitsrayim ketho'afot re'em lo</strong>: The wild ox (<em>re'em</em>) image returns from 23:22 — God who brought Israel from Egypt with wild ox strength now acts through Israel's king: 'he will devour hostile nations, crush their bones, and shatter them with his arrows.' The military imagery — devouring, bone-crushing, arrow-shattering — describes Israel as the instrument of divine warfare against the nations. This is conquest language that anticipates the campaigns Israel will conduct under Joshua.</p>",
    "9": "<p><strong>kara shakav ka'ari vekalavi mi yiqimenu</strong>: 'He crouches and lies down like a lion or a lioness — who dares rouse him?' The lion-at-rest image from 23:24 returns, but now adds the Abrahamic formula: 'Blessed is everyone who blesses you (<em>mevarekheikha varukh</em>) and cursed is everyone who curses you (<em>ore'arekha arur</em>).' This is the verbatim reversal of Balak's initial hope (22:6) and the precise language of Gen 12:3 applied to Israel as a nation. Balaam, hired to curse, delivers the Abrahamic blessing formula over the nation he was meant to curse.</p>",
    "10": "<p><strong>vayichar af Balaq el Bil'am vayispoq et kappav</strong>: 'Balak was furious with Balaam and struck his palms together' — the clapping/striking of palms is a gesture of outrage or dismissal (cf. Job 27:23; Lam 2:15 where it signals scorn). Balak's final accusation — 'I called you to curse my enemies but you have blessed them three times (<em>shalosh pe'amim</em>)' — summarizes the entire narrative pattern. The counting of three blessings marks the completeness of the reversal: every opportunity for cursing was transformed into blessing.</p>",
    "11": "<p><strong>veattah borah lekha el meqomekha amarti kabbed akabedekha vehineh mena'akha YHWH mikkavod</strong>: 'Now go back to your home! I intended to honor you greatly, but YHWH has kept that honor from you.' <em>Mena'akha YHWH mikkavod</em> (YHWH has withheld honor from you) — the passive construction makes Balak acknowledge YHWH's role in the outcome, even in his anger. He blames not Balaam but YHWH for the failure of his plan.</p>",
    "12": "<p>Balaam's response reminds Balak that he warned the initial messengers that his speech was divinely controlled (22:18). The narrative circles back to the prophetic constraint established at the start — completing a frame around the entire oracle sequence.</p>",
    "13": "<p><strong>im yitten li Balaq melo beto kesef vezahav lo ukhal la'avor et pi YHWH la'asot tovah o ra'ah millivi</strong>: The financial immunity declaration — even a palace full of silver and gold cannot purchase a curse against Israel. The phrase <em>la'asot tovah o ra'ah millivi</em> (to do good or evil of my own will) is significant: Balaam is not constrained by professional ethics but by divine command. He cannot even produce a voluntary blessing or curse — all his speech is under divine control.</p>",
    "14": "<p><strong>veattah hineni holekh le'ammi lekha iy'atsekha asher ya'aseh ha'am hazeh le'ammekha be'acharit hayamim</strong>: 'Let me warn you what this people will do to your people in the days to come (<em>be'acharit hayamim</em>).' The phrase <em>be'acharit hayamim</em> (in the latter days/end of days) is the standard prophetic temporal frame for eschatological oracle — it appears in Balaam's famous Star oracle (v17) and in Jacob's deathbed blessings (Gen 49:1). What follows is the most explicitly messianic oracle in Numbers.</p>",
    "15": "<p><strong>vayissa meshalow vayomar ne'um Bil'am ben Be'or une'um haggever shetum ha'ayin</strong>: The fourth oracle repeats the formula of vv.3-4 almost verbatim — establishing it as a paired companion to the third oracle. The repetition of <em>shetum ha'ayin</em> (whose eye is opened) emphasizes that what follows is revealed vision, not political prediction.</p>",
    "16": "<p><strong>ne'um shome'a imrei El veyode'a da'at Elyon machazeh Shaddai yechezeh nopel ugeluy einayim</strong>: The fourth oracle credential formula adds <em>veyode'a da'at Elyon</em> (one who knows the knowledge of the Most High). <em>Elyon</em> (Most High) is the divine title associated with pre-Israelite worship in Jerusalem (Gen 14:18-22, Melchizedek's god) and with Psalm 91. The expansion of the credential formula for the fourth oracle — adding Most High knowledge to the third oracle's Spirit-anointing — signals that the fourth oracle is the culminating revelation.</p>",
    "17": "<p><strong>er'ennu velo attah ashurennu velo qarov darakh kokhav miYa'aqov veqam shevet miYisra'el</strong>: 'I see him, but not now; I behold him, but not near. A Star shall come out of Jacob and a Scepter shall rise from Israel.' This is the primary messianic oracle of Numbers and one of the most important in the entire OT. Key terms: <em>kokhav</em> (star) — celestial body associated with divine messengers and royal destiny; <em>shevet</em> (scepter/rod/tribe) — the ruler's rod that identifies kingship, also Jacob's blessing for Judah (Gen 49:10: 'the scepter shall not depart from Judah'). The temporal markers <em>velo attah...velo qarov</em> (not now...not near) explicitly frame this as long-range prophecy. Simon bar Kokhba (132-135 CE) took his messianic name from this verse. The Magi's star in Matt 2 is read in the church fathers as a fulfillment of Balaam's oracle — the Gentile star-seer from Mesopotamia has Mesopotamian successors who follow the star to the Davidic Messiah.</p>",
    "18": "<p><strong>vehayah Edom yerushah vehayah yerushah Se'ir oyevav veYisra'el 'oseh chayil</strong>: 'Edom will become a possession, Seir his enemy a possession, but Israel will act valiantly.' Edom (the territory and descendants of Esau/Seir) is the first named target of the Star-Scepter's conquest. The partial fulfillment in David's subjugation of Edom (2 Sam 8:14) is the historical referent; the eschatological reading sees this as the Messiah's complete victory over all enemy nations. The word <em>yerushah</em> (possession, inheritance) is the same root as <em>yarash</em> (to inherit/dispossess) used throughout the conquest narratives.</p>",
    "19": "<p><strong>veyerd miYa'aqov vehe'evid sarid me'ir</strong>: 'A ruler will come from Jacob and destroy the survivors of the city.' The brevity of this verse intensifies the finality — the ruler's authority extends to total conquest. The phrase <em>sarid me'ir</em> (survivor of the city) may refer to Edom's fortified cities or to the general category of all enemy strongholds. The oracle does not name the Messiah but describes the scope of his rule.</p>",
    "20": "<p><strong>vayar et Amaleq vayissa meshalow vayomar reshit goyim Amaleq ve'acharito adei oved</strong>: Balaam sees Amalek and delivers the fifth oracle: 'Amalek was first among the nations, but its end is destruction.' <em>Reshit goyim</em> (first of nations) may refer to Amalek's early military prominence (first nation to attack Israel after the Exodus, Exod 17:8-16) rather than chronological priority. The oracle pronounces Amalek's terminal fate — <em>adei oved</em> (unto destruction/perishing), the same root as in Gen 2:15's garden-keeping charge. The Amalek oracle is the dark counterpart to the Israel-blessing oracles.</p>",
    "21": "<p><strong>vayar et haQeini vayissa meshalow vayomar eitan moshavekha vesim batsur qinnekha</strong>: The Kenite oracle: 'Your dwelling place is secure (<em>eitan</em>, permanent/enduring), your nest (<em>qinekha</em>) is set in rock.' The Kenites (Cain's descendants, associated with Moses's father-in-law Hobab/Jethro) were semi-nomadic metalworkers who lived in rocky terrain. The word <em>qen</em> (nest) is a pun on <em>Qeni</em> (Kenite). Their security is acknowledged before the oracle turns to their destruction.</p>",
    "22": "<p><strong>ki im yihyeh levu'er Qayin ad mah Ashshur tishbekha</strong>: 'Yet the Kenite will be burned up (<em>boa'er</em>, consumed by fire, from <em>ba'ar</em>) when Asshur takes you captive.' The Kenite oracle has two parts: security (v21) and eventual destruction by Assyria (v22). <em>Asshur</em> (Assyria) as the instrument of destruction connects this to the later Assyrian deportations (8th century BCE) that fulfilled similar prophetic oracles.</p>",
    "23": "<p><strong>vayissa meshalow vayomar oy mi yichyeh mishum El eleh</strong>: 'Alas, who can survive when God brings these things about?' The seventh oracle begins with the exclamation <em>oy</em> (woe/alas) — the prophetic woe formula. The oracle is brief and oracular about cosmic-scale events that even the speaker does not fully explain.</p>",
    "24": "<p><strong>vetsim me'yad Kittim ve'inu Ashshur ve'inu Ever vegam hu adei oved</strong>: 'Ships from the coasts of Kittim will oppress Asshur and Eber, but they too will come to ruin.' <em>Kittim</em> in Numbers probably refers to the Mediterranean coastal peoples (Cyprus, later used more broadly for western maritime powers including Greece and Rome in Daniel 11:30). The oracle's historical scope extends to Greek or Roman maritime expansionism — a vision far beyond Balaam's immediate context. The final <em>adei oved</em> (unto destruction) mirrors the Amalek oracle — all the nations' power ends in ruin.</p>",
    "25": "<p><strong>vayaqom Bil'am vayelekh vayashov limqomo vegam Balaq halakh ledarko</strong>: 'Then Balaam got up and returned to his home, and Balak went his way.' The abrupt ending — two parties simply departing, no farewell, no ceremony — underscores the anti-climax of Balak's enterprise. He came with silver and a professional curse; he leaves with nothing, the curse transformed into blessing. The narrative irony is complete. The final note that Balak 'went his way (<em>ledarko</em>)' closes a narrative in which his intended path (the path of cursing Israel) was blocked at every turn — he returns to his own path, having failed entirely.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'numbers')
    merge_comm(c, ORIGINAL)
    save_comm('mkt-original', 'numbers', c)
    print('Numbers 22-24 original written.')

if __name__ == '__main__':
    main()
